<script>
  const menuToggle = document.getElementById('menuToggle');
  const menuClose = document.getElementById('menuClose');
  const menuOverlay = document.getElementById('menuOverlay');
  const mobileMenu = document.getElementById('mobileMenu');

  function openMenu() {
    menuOverlay.classList.add('active');
    mobileMenu.classList.add('active');
    document.body.style.overflow = 'hidden';
  }
  function closeMenu() {
    menuOverlay.classList.remove('active');
    mobileMenu.classList.remove('active');
    document.body.style.overflow = '';
  }

  if (menuToggle) menuToggle.addEventListener('click', openMenu);
  if (menuClose) menuClose.addEventListener('click', closeMenu);
  if (menuOverlay) menuOverlay.addEventListener('click', closeMenu);

  document.querySelectorAll('.mobile-accordion-trigger').forEach(btn => {
    btn.addEventListener('click', () => {
      const acc = btn.closest('.mobile-accordion');
      const isOpen = acc.classList.contains('open');
      document.querySelectorAll('.mobile-accordion').forEach(a => a.classList.remove('open'));
      if (!isOpen) acc.classList.add('open');
    });
  });

  document.querySelectorAll('.nav-dropdown-wrap').forEach(wrap => {
    let timeout;
    wrap.addEventListener('mouseenter', () => {
      clearTimeout(timeout);
      document.querySelectorAll('.nav-dropdown-wrap').forEach(w => w.classList.remove('active'));
      wrap.classList.add('active');
    });
    wrap.addEventListener('mouseleave', () => {
      timeout = setTimeout(() => wrap.classList.remove('active'), 120);
    });
  });
</script>
